import { Component, signal } from '@angular/core';
import { RouterOutlet } from '@angular/router';

@Component({
  selector: 'app-root',
  imports: [RouterOutlet],
  template: '<router-outlet></router-outlet>'
})
export class App {
  protected readonly title = signal('projeto-gestao');
}

import { Injectable, signal, computed } from '@angular/core';
import {
  User,
  Column,
  Task,
  UserMetric,
  BoardState,
} from '@core/models/interfaces';
import { SeedDataService } from './seed-data.service';

const STORAGE_KEY = 'board_state_v1';

@Injectable({ providedIn: 'root' })
export class BoardStateService {
  // We'll initialize the signal in the constructor because getInitialState
  // depends on an injected service (SeedDataService). Initializing with
  // `this.getInitialState()` in a field initializer would run before
  // dependency injection is complete.
  private _state = signal<BoardState>({ users: [], columns: [], tasks: [], metrics: [], lastUpdated: '' });

  readonly users = computed(() => this._state().users);
  readonly columns = computed(() => [...this._state().columns].sort((a, b) => a.sequence - b.sequence));
  readonly tasks = computed(() => this._state().tasks);
  readonly metrics = computed(() => this._state().metrics);

  constructor(private seedDataService: SeedDataService) {
	// populate initial state (from storage or seed)
	this._state.set(this.getInitialState());
  }

  getInitialState(): BoardState {
	const raw = localStorage.getItem(STORAGE_KEY);
	if (raw) {
	  try {
		const parsed = JSON.parse(raw) as BoardState;
		// map string dates back to Date objects for tasks
		parsed.tasks = (parsed.tasks || []).map((t: any) => ({
		  ...t,
		  deadline: t.deadline ? new Date(t.deadline) : null,
		  createdAt: t.createdAt ? new Date(t.createdAt).toISOString() : new Date().toISOString(),
		  updatedAt: t.updatedAt ? new Date(t.updatedAt).toISOString() : new Date().toISOString(),
		}));
		return parsed;
	  } catch (err) {
		console.warn('Failed to parse board state from LocalStorage, falling back to seed data', err);
	  }
	}

	// No persisted state -> build initial state from seed data
	const users: User[] = this.seedDataService.getUsers();
	const columns: Column[] = this.seedDataService.getFixedColumns();
	const tasks: Task[] = this.seedDataService.getSeedTasks();

	const initial: BoardState = {
	  users,
	  columns,
	  tasks,
	  metrics: [],
	  lastUpdated: new Date().toISOString(),
	};

	// Save the initial state to LocalStorage (stringified)
	try {
	  localStorage.setItem(STORAGE_KEY, JSON.stringify(initial));
	} catch (err) {
	  console.warn('Unable to persist initial board state to LocalStorage', err);
	}

	return initial;
  }

  private saveToStorage(state: BoardState): void {
	const copy: BoardState = { ...state, lastUpdated: new Date().toISOString() };
	try {
	  localStorage.setItem(STORAGE_KEY, JSON.stringify(copy));
	  // update the signal with the persisted copy
	  this._state.set(copy);
	} catch (err) {
	  console.warn('Failed to save board state to LocalStorage', err);
	}
  }

  // --- Mutation skeletons (implementations to be added) ---
  addTask(task: Omit<Task, 'id' | 'createdAt' | 'updatedAt'>): void {
	// TODO: implement creating id, timestamps, inserting into state and persisting
  }

  updateTask(task: Task): void {
	// TODO: implement updating task in state and persisting
  }

  moveTask(taskId: string, targetColumnId: string): void {
	// TODO: implement move semantics, validation (e.g. reviewer requirement) and persist
  }

  addColumn(columnName: string): void {
	// TODO: implement adding a new dynamic column between Ready and Teste
  }

  calculateMetrics(): void {
	// TODO: implement throughput, WIP, and deadline alerts calculation
  }
}

