getFixedColumns(): Column[] { return [ { id: 'col-backlog', name: 'Backlog', sequence: 0, isFixed: true }, { id: 'col-ready', name: 'Ready', sequence: 1, isFixed: true }, // custom columns will be inserted between Ready and Teste { id: 'col-teste', name: 'Teste', sequence: 3, isFixed: true }, { id: 'col-feito', name: 'Feito', sequence: 4, isFixed: true }, { id: 'col-cancelado', name: 'Cancelado', sequence: 5, isFixed: true }, ]; }
